Here's a C# implementation of this algorithm:

```csharp
public class Item
{
    public DateTime CreatedAt { get; set; }
    public int Popularity { get; set; }
    public double Gravity
    {
        get
        {
            if (CreatedAt > DateTime.Now)
                return 0;
            else if (Popularity > 0)
                return 1;
            else
                return -1;
        }
    }
}

public class Program
{
    public static void Main()
    {
        var items = new List<Item>
        {
            new Item { CreatedAt = DateTime.Now.AddDays(-1), Popularity = 10 },
            new Item { CreatedAt = DateTime.Now.AddDays(-2), Popularity = 5 },
            new Item { CreatedAt = DateTime.Now.AddDays(-3), Popularity = 0 },
            new Item { CreatedAt = DateTime.Now, Popularity = 15 },
            new Item { CreatedAt = DateTime.Now.AddDays(1), Popularity = 10 },
        };

        items.Sort((x, y) => y.Gravity.CompareTo(x.Gravity));

